func (o *Category) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Category":
		rel, ok := retrieved.(*Category)
		if !ok {
			return fmt.Errorf("category cannot load %T as %q", retrieved, name)
		}

		o.R.Category = rel

		if rel != nil {
			rel.R.Category = o
		}
		return nil
	case "ReverseCategories":
		rels, ok := retrieved.(CategorySlice)
		if !ok {
			return fmt.Errorf("category cannot load %T as %q", retrieved, name)
		}

		o.R.ReverseCategories = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.ReverseCategories = CategorySlice{o}
			}
		}
		return nil
	case "Workspace":
		rel, ok := retrieved.(*Workspace)
		if !ok {
			return fmt.Errorf("category cannot load %T as %q", retrieved, name)
		}

		o.R.Workspace = rel

		if rel != nil {
			rel.R.Categories = CategorySlice{o}
		}
		return nil
	case "Transactions":
		rels, ok := retrieved.(TransactionSlice)
		if !ok {
			return fmt.Errorf("category cannot load %T as %q", retrieved, name)
		}

		o.R.Transactions = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Category = o
			}
		}
		return nil
	default:
		return fmt.Errorf("category has no relationship %q", name)
	}
}

