type categoryJoins[Q dialect.Joinable] struct {
	typ               string
	Category          modAs[Q, categoryColumns]
	ReverseCategories modAs[Q, categoryColumns]
	Workspace         modAs[Q, workspaceColumns]
	Transactions      modAs[Q, transactionColumns]
}

func (j categoryJoins[Q]) aliasedAs(alias string) categoryJoins[Q] {
	return buildCategoryJoins[Q](buildCategoryColumns(alias), j.typ)
}

func buildCategoryJoins[Q dialect.Joinable](cols categoryColumns, typ string) categoryJoins[Q] {
	return categoryJoins[Q]{
		typ: typ,
		Category: modAs[Q, categoryColumns]{
			c: Categories.Columns,
			f: func(to categoryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Categories.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.WorkspaceID), to.ID.EQ(cols.ParentID),
					))
				}

				return mods
			},
		},
		ReverseCategories: modAs[Q, categoryColumns]{
			c: Categories.Columns,
			f: func(to categoryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Categories.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.WorkspaceID), to.ParentID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Workspace: modAs[Q, workspaceColumns]{
			c: Workspaces.Columns,
			f: func(to workspaceColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Workspaces.Name().As(to.Alias())).On(
						to.ID.EQ(cols.WorkspaceID),
					))
				}

				return mods
			},
		},
		Transactions: modAs[Q, transactionColumns]{
			c: Transactions.Columns,
			f: func(to transactionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Transactions.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.WorkspaceID), to.CategoryID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
